#include <iostream>#include <string>#include <vector>#include <algorithm>#include <limits>struct JobOffer {    std::string company_name;    std::string location;    int monthly_salary_rmb;    int monthly_housing_stipend;    bool has_996_culture;    bool has_stock_options;    int sign_on_bonus;};void print_offer(const JobOffer& offer, int index);void print_all_offers(const std::vector<JobOffer>& offers);int calculate_annual_total(const JobOffer& offer);double calculate_monthly_effective(const JobOffer& offer);std::vector<JobOffer> filter_no_996(const std::vector<JobOffer>& offers);JobOffer find_best_financial_offer(const std::vector<JobOffer>& offers);JobOffer find_best_work_life_balance(const std::vector<JobOffer>& offers);void print_recommendation(const std::vector<JobOffer>& offers);int main() {	std::cout << "\n========================================\n";	std::cout << "   CHINESE TECH JOB OFFER ANALYZER v1.0\n";	std::cout << "   (Brutally Honest Edition)\n";	std::cout << "========================================\n\n";	std::vector<JobOffer> offers {		{"ByteDance", "Beijing", 28000, 1500, true, true, 30000},		{"Tencent", "Shenzhen", 26000, 2000, true, true, 25000},		{"Alibaba", "Hangzhou", 27000, 1000, true, true, 28000},		{"Xiaomi", "Beijing", 22000, 1000, false, false, 15000},		{"Huawei", "Shenzhen", 25000, 0, true, false, 20000},		{"Pinduoduo", "Shanghai", 30000, 1500, true, true, 40000}	};	int choice = 0;	while (choice != 6) {		std::cout << "\n--- MENU ---\n"			  << "1. View all offers\n"			  << "2. Filter out 996 companies\n"			  << "3. Find best financial offer\n"			  << "4. Find best work-life balance\n"			  << "5. Get final recommendation\n"			  << "6. Exit\n"			  << "Enter choice: ";		std::cin >> choice;		std::cin.ignore(std::numeric_limits<std::streamsize>::max(), '\n');		switch (choice) {			case 1:				print_all_offers(offers);				break;			case 2: {				auto no_996 = filter_no_996(offers);				std::cout << "\n=== OFFERS WITHOUT 996 ===\n";				if (no_996.empty()) {					std::cout << "No offers without 996. Welcome to Chinese tech.\n";				} else {					print_all_offers(no_996);				}				break;			} case 3: {				JobOffer best = find_best_financial_offer(offers);				std::cout << "\n=== BEST FINANCIAL OFFER ===\n";				print_offer(best, -1);				break;			} case 4: {				JobOffer best_wlb = find_best_work_life_balance(offers);				std::cout << "\n=== BEST WORK-LIFE BALANCE ===\n";				print_offer(best_wlb, -1);				break;			} case 5:				print_recommendation(offers);				break;			case 6:				std::cout << "Exiting. Remember: The best offer is the one that lets you keep learning.\n";				break;			default:				std::cout << "Invalid choice. Try again.\n";		}	}	return 0;}void print_offer(const JobOffer& offer, int index) {    if (index >= 0) {        std::cout << "[" << index << "] ";    }    std::cout << "🏢 " << offer.company_name << " | " << offer.location << "\n";    std::cout << "   💰 Base: ¥" << offer.monthly_salary_rmb << "/month\n";    std::cout << "   🏠 Housing: ¥" << offer.monthly_housing_stipend << "/month\n";    std::cout << "   📅 Annual Total (est.): ¥" << calculate_annual_total(offer) << "\n";    std::cout << "   ⚠️  996 Culture: " << (offer.has_996_culture ? "YES 😭" : "No (allegedly)") << "\n";    std::cout << "   📈 Stock Options: " << (offer.has_stock_options ? "Yes 📊" : "No") << "\n";    std::cout << "   🎁 Sign-on Bonus: ¥" << offer.sign_on_bonus << "\n";    std::cout << "   📊 Effective Monthly (with housing): ¥" << calculate_monthly_effective(offer) << "\n\n";}void print_all_offers(const std::vector<JobOffer>& offers) {    std::cout << "\n=== ALL OFFERS (" << offers.size() << ") ===\n";    for (size_t i = 0; i < offers.size(); i++) {        print_offer(offers[i], i);    }}int calculate_annual_total(const JobOffer& offer) {    // Assume 13th month salary (common in China) + 2-3 month bonus    // This is simplified    int base_annual = offer.monthly_salary_rmb * 12;    int housing_annual = offer.monthly_housing_stipend * 12;    int bonus_estimate = offer.monthly_salary_rmb * 2; // conservative 2-month bonus    return base_annual + housing_annual + bonus_estimate + offer.sign_on_bonus;}double calculate_monthly_effective(const JobOffer& offer) {    return offer.monthly_salary_rmb + offer.monthly_housing_stipend;}std::vector<JobOffer> filter_no_996(const std::vector<JobOffer>& offers) {    std::vector<JobOffer> result;    for (const auto& offer : offers) {        if (!offer.has_996_culture) {            result.push_back(offer);        }    }    return result;}JobOffer find_best_financial_offer(const std::vector<JobOffer>& offers) {    // Assume at least one offer    JobOffer best = offers[0];    int best_total = calculate_annual_total(offers[0]);    for (const auto& offer : offers) {        int total = calculate_annual_total(offer);        if (total > best_total) {            best = offer;            best_total = total;        }    }    return best;}JobOffer find_best_work_life_balance(const std::vector<JobOffer>& offers) {    // First, filter non-996. If none, just pick the one with highest salary among 996 (dark humor)    auto no_996 = filter_no_996(offers);    if (!no_996.empty()) {        // Among non-996, pick highest salary        return find_best_financial_offer(no_996);    } else {        // All are 996. Pick the one with highest pay (might as well get paid for suffering)        std::cout << "Warning: All offers have 996 culture. Picking best financial among suffering.\n";        return find_best_financial_offer(offers);    }}void print_recommendation(const std::vector<JobOffer>& offers) {    std::cout << "\n========================================\n";    std::cout << "        FINAL RECOMMENDATION\n";    std::cout << "========================================\n";    JobOffer best_finance = find_best_financial_offer(offers);    JobOffer best_wlb = find_best_work_life_balance(offers);    std::cout << "\n💰 MAXIMIZE MONEY:\n";    print_offer(best_finance, -1);    std::cout << "\n🧘 MAXIMIZE SANITY (Avoid 996):\n";    print_offer(best_wlb, -1);    std::cout << "\n--- BRUTALLY HONEST ADVICE ---\n";    if (best_finance.company_name == best_wlb.company_name) {        std::cout << "Take the " << best_finance.company_name << " offer. It's the best of both worlds.\n";    } else {        std::cout << "The " << best_finance.company_name << " offer pays more (¥"                   << calculate_annual_total(best_finance) << " vs ¥" << calculate_annual_total(best_wlb) << ").\n";        std::cout << "But " << best_wlb.company_name << " won't destroy your soul.\n";        std::cout << "In China, 3 years at a 996 company ages you 5 years. Choose wisely.\n";    }    std::cout << "\nAnd remember: In 2025, the market is frozen. An offer is an offer.\n";    std::cout << "But never stop interviewing. The best leverage is another offer.\n";    std::cout << "========================================\n";}